import React, { useState, useMemo, useEffect } from "react";

const DATA = {"nodes": [{"id": "n_root", "parent_id": null, "evidence_quality": "well-evidenced", "label": "What does the evidence show about microplastics \u2014 where they come from, whether we can measure them, and what they do to health and the environment?", "children": ["n_measure", "n_origin", "n_health", "n_environ", "n_policy"], "role": "topic", "question": {"research": "What does the evidence show about microplastics \u2014 where they come from, whether we can measure them, and what they do to health and the environment?", "simple": "Are microplastics harming us?"}, "depends_on": {"research": "'Harming us' is not one measurable quantity. The literature separately measures whether microplastic concentrations can be measured consistently at all, whether the particles are reliably found inside the human body or are largely laboratory contamination, where they originate, whether human burden is associated with disease, whether controlled studies show harm at realistic doses, whether wild organisms are harmed at realistic concentrations, and what source policy changes \u2014 with sharply different degrees of consensus, and with the PRESENCE questions far better evidenced than the HARM questions. Public debate routinely lets 'microplastics are everywhere' stand in for 'microplastics are hurting you'; this tree exists to keep them apart.", "simple": "There's no single 'are they harming us' score. Whether we can even measure microplastics reliably, whether they're truly inside our bodies or just contamination in the lab, where they come from, whether people with more of them get sicker, whether experiments show harm at real-world amounts, whether they hurt wildlife, and whether bans work are different questions with very different-quality evidence. That we can find the particles almost everywhere is far better established than that they hurt us. Pick one."}, "coverage_note": "Authored dimensions: measurement/detection reliability, environmental origin, human-health association, controlled human-harm evidence, ecological harm, and source policy. DELIBERATELY NOT COVERED (invisible to this tool): the plastic-additive chemicals that leach from particles (bisphenols, phthalates, flame retardants) as a separate toxicology, scored only where a health finding bundles them; nanoplastics as a distinct class except where a cited study reports micro- AND nano-plastics together; airborne/indoor exposure and ingestion-vs-inhalation route apportionment beyond what a finding carries; the climate/carbon footprint of plastics; macroplastic entanglement and ingestion (turtles, seabirds) as distinct from micro-scale effects; economic-cost estimates; and whether plastic production or use SHOULD be restricted all things considered \u2014 a values question this tool records no verdict on. Absence is a scope choice, not evidence of no effect. Three definitional boundaries: 'present' is not 'harmful' (detecting a particle in a tissue is not evidence it damages it); 'harm at high laboratory dose' is not 'harm at environmental concentration'; and 'microplastic' (<5 mm) is not 'nanoplastic' (<1 \u00b5m) \u2014 findings must not silently swap them.", "scored": false, "evidence_caveats": ["presence is far better evidenced than harm \u2014 confidence on 'microplastics are everywhere' does not transfer to 'microplastics are harming us'"]}, {"id": "n_measure", "parent_id": "n_root", "evidence_quality": "thin", "label": "Can we even measure microplastics and our exposure to them reliably?", "children": ["n_measure_reliable", "n_measure_body"], "role": "dimension", "question": {"research": "Can microplastic concentrations, and their presence inside the human body, be measured reliably \u2014 or are the numbers method-dependent and vulnerable to contamination?", "simple": "Can we actually measure microplastics reliably, in the environment and in us?"}, "depends_on": {"research": "Two separable measurement questions. First, whether different laboratories analysing the same sample get consistent concentrations (cross-lab reproducibility) \u2014 if not, every downstream exposure number carries that error. Second, whether particles reported inside human tissue are genuinely there rather than contamination introduced during sampling and analysis, given that plastics are ubiquitous in labs. A method can be irreproducible across labs yet still detect something real, or a detection can be real yet the concentration wrong \u2014 the two failures are different and are scored separately.", "simple": "Two different questions. One: if two labs measure the same water, do they get the same number? (Often not.) Two: when a study says it found plastic in blood or placenta, is that really from the body, or did stray plastic from the lab get in? Those are separate ways the measurements could be shaky, and they're scored apart."}, "coverage_note": "Covers cross-laboratory reproducibility of quantification and the contamination-vs-real-signal question for human-tissue detection. Does not adjudicate any single analytical technique (Pyr-GC/MS vs FTIR vs Raman vs Nile Red) as a whole, nor the separate question of what size classes current methods can even see.", "scored": false, "evidence_caveats": ["measurement validity is itself contested \u2014 read every exposure and harm number in that light"]}, {"id": "n_measure_reliable", "parent_id": "n_measure", "evidence_quality": "thin", "label": "Can microplastic concentrations be measured consistently across different laboratories and methods?", "children": [], "role": "leaf", "question": {"research": "Can microplastic concentrations be measured consistently across different laboratories and methods?", "simple": "If different labs measure the same sample, do they get the same answer?"}, "claim_evaluated": {"research": "Microplastic concentrations can be measured consistently across laboratories and methods \u2014 results are reproducible rather than strongly dependent on which lab, protocol, and instrument produced them.", "simple": "Microplastic measurements are reliable enough that different labs analysing the same sample get about the same number."}, "depends_on": {"research": "Reproducibility is measured, not asserted: interlaboratory ring trials in which many labs analyse identical materials and the between-lab spread is quantified. When that spread is large (reproducibility spanning tens of percent), a reported concentration is as much an artefact of method choice \u2014 size threshold, digestion, spectroscopy vs thermal analysis \u2014 as of the sample. Low reproducibility undercuts what any exposure or association number can mean, because the exposure is being measured inconsistently.", "simple": "This is testable: give many labs the same material and see how close their answers land. In the big shared test they were far apart \u2014 the number you get depends heavily on the method used. If labs can't agree on the amount, it's hard to trust exposure figures built on those measurements."}, "scored": true, "evidence_caveats": ["rests on interlaboratory comparison exercises; the VAMAS 2025 ring trial (84 labs) is the load-bearing evidence", "no qualifying FOR located \u2014 one-sided", "fast-moving: Re-check whether achieved cross-laboratory reproducibility (ISO/VAMAS standardisation) has been demonstrated before any republish \u2014 the FOR side is standardisation-in-progress at authoring time."]}, {"id": "n_measure_body", "parent_id": "n_measure", "evidence_quality": "well-evidenced", "label": "Are microplastics reliably detected inside the human body, rather than being sampling/laboratory contamination?", "children": [], "role": "leaf", "question": {"research": "Are microplastics reliably detected inside the human body (blood, placenta, tissue), rather than being sampling or laboratory contamination?", "simple": "Is the plastic that studies find in the body really from the body \u2014 not from the lab?"}, "claim_evaluated": {"research": "Microplastics are reliably detected inside the human body (blood, placenta, tissues) at levels indicating genuine internal exposure \u2014 the detections reflect particles that were in the body, not contamination introduced during sampling and analysis.", "simple": "When studies report microplastics in blood, placenta, or organs, the particles were genuinely in the body \u2014 not contamination picked up in the lab."}, "depends_on": {"research": "Depends on the analytical quality control: because plastics pervade laboratory air, clothing, and labware, a detection is only credible if procedural blanks, blank-correction, and anti-contamination controls rule out external plastic \u2014 and if the polymers are confirmed spectroscopically rather than by stain alone (tissue lipids and proteins are known false positives). Early studies often lacked these controls; studies that added them tend to report lower, more realistic concentrations. So the leaf turns on whether the positive detections survive contamination control, not on whether particles were reported.", "simple": "The catch is that plastic is everywhere in a lab \u2014 in the air, on clothes, in the equipment \u2014 so a 'positive' result only counts if the study ran clean 'blank' controls to prove the plastic didn't come from the lab, and confirmed it was really plastic (fat and protein in tissue can fool the test). Early studies often skipped this; careful ones tend to find less. So the question is whether the finding survives those checks."}, "scored": true, "evidence_caveats": ["all human-tissue detections inherit a contamination risk; concentrations from studies without rigorous procedural blanks may be overestimates"]}, {"id": "n_origin", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "Where do microplastics come from?", "children": ["n_origin_sources"], "role": "dimension", "question": {"research": "Where do microplastics come from, and are the sources quantified well enough to act on?", "simple": "Where do microplastics actually come from?"}, "depends_on": {"research": "That microplastics are human-made is not in dispute; the live questions are which sources dominate, how confidently they are quantified, and whether the environmentally dominant fraction (secondary particles from the fragmentation of larger plastic waste) can be attributed at all. Source-apportionment estimates are model-dependent and carry wide uncertainty, so 'we know where they come from' can be true at the level of naming sources yet weak at the level of quantifying and ranking them for policy.", "simple": "Nobody argues microplastics are natural \u2014 they come from plastic, which is human-made. The real questions are which sources are biggest, how sure we are of the numbers, and whether we can even track the largest kind (bits that break off from bigger plastic litter). Naming the sources is easier than measuring them precisely."}, "coverage_note": "Covers whether dominant sources are identified and quantified well enough to prioritise. Does not separately score airborne vs waterborne pathways, marine vs freshwater vs terrestrial partitioning, or the fate/transport of particles once released \u2014 only where a finding carries them.", "scored": false, "evidence_caveats": ["source apportionment covers primary microplastics (15\u201331% of the total); the dominant secondary fraction is poorly quantified"]}, {"id": "n_origin_sources", "parent_id": "n_origin", "evidence_quality": "well-evidenced", "label": "Are the major sources of microplastic pollution identified and quantified well enough to target the biggest contributors?", "children": [], "role": "leaf", "question": {"research": "Are the major sources of microplastic pollution identified and quantified well enough to target the biggest contributors?", "simple": "Do we know where most microplastics come from well enough to do something about it?"}, "claim_evaluated": {"research": "The major sources of microplastic pollution are identified and quantified well enough to target the biggest contributors \u2014 notably tyre-wear particles, synthetic-textile fibres, and the fragmentation of larger plastic waste.", "simple": "We know the main sources of microplastics well enough to target the biggest ones \u2014 tyre wear, clothing fibres, and larger plastic breaking down.", "_note": null}, "depends_on": {"research": "Depends on whether source-apportionment inventories converge on a small set of dominant, actionable sources \u2014 and on how the dominant ENVIRONMENTAL fraction (secondary fragmentation) is handled. Primary-microplastic inventories (tyre wear, textiles, pellets, microbeads) can rank sources, but they cover only the 15\u201331% of ocean plastic that is primary; the larger secondary fraction is poorly quantified. So 'well enough to act' is stronger for primary sources than for the total.", "simple": "It depends on whether the studies that add up sources agree on a few big ones you could actually act on \u2014 and on the fact that the biggest environmental share is old plastic breaking into fragments, which is hard to trace. We can rank the deliberately-made small plastics (tyres, fibres, beads) better than we can pin down the fragments."}, "scored": true, "evidence_caveats": ["FOR evidence is a modelled global apportionment with wide uncertainty; regional source shares differ, and it addresses only the primary fraction"]}, {"id": "n_health", "parent_id": "n_root", "evidence_quality": "thin", "label": "Do microplastics harm human health?", "children": ["n_health_assoc", "n_health_cause"], "role": "dimension", "question": {"research": "Do microplastics harm human health \u2014 is there a measured association with disease, and does controlled evidence show harm at realistic exposure?", "simple": "Do microplastics actually make people ill?"}, "depends_on": {"research": "Two separable questions with different designs. Whether human microplastic burden is ASSOCIATED with disease rests on observational human studies \u2014 currently essentially one contested study. Whether microplastics CAUSE harm rests on controlled animal and in-vitro models, where the pivotal issue is dose: most experiments use concentrations far above real human exposure. Neither the presence of particles in the body nor harm at a high laboratory dose establishes harm at the amounts people actually encounter.", "simple": "Two different questions. One: do people with more microplastics in them get sicker? (Almost the only human study on this is hotly disputed.) Two: do lab experiments prove harm? (They often do \u2014 but usually at doses far higher than anyone is really exposed to.) Finding particles in the body, or harm at huge lab doses, isn't the same as harm at real-life amounts."}, "coverage_note": "Covers the observational human association and controlled-model causal evidence for microplastic PARTICLES. The toxicology of additive chemicals that leach from plastics (bisphenols, phthalates) is out of scope except where a finding bundles them. Long-term human disease endpoints cannot be tested experimentally in people, so the causal leaf relies on animal/in-vitro models with the attendant extrapolation caveat.", "scored": false, "evidence_caveats": ["the human-harm evidence is early and thin; neither presence in the body nor high-dose laboratory harm establishes harm at real exposure"]}, {"id": "n_health_assoc", "parent_id": "n_health", "evidence_quality": "thin", "label": "Is higher microplastic exposure or internal burden associated with worse human health outcomes?", "children": [], "role": "leaf", "question": {"research": "Is higher microplastic exposure or internal burden associated with worse human health outcomes?", "simple": "Do people with more microplastics in them have worse health?"}, "claim_evaluated": {"research": "Higher microplastic exposure or internal burden is associated with worse human health outcomes (e.g. cardiovascular events).", "simple": "People with more microplastics in their bodies have measurably worse health."}, "depends_on": {"research": "Depends almost entirely on one study: Marfella et al. (NEJM 2024) found carotid-plaque patients with detectable micro- and nanoplastics had a ~4.5\u00d7 rate of heart attack, stroke, or death over ~34 months. It is a single observational cohort whose exposure measurement drew formal contamination critiques, and the authors state it does not prove causation. There is no body of replication; the leaf is genuinely thin, and whether the association is real, confounded, or a measurement artefact is unresolved.", "simple": "This rides on essentially one study: people whose artery plaque contained microplastics had about 4.5 times the rate of heart attacks, strokes, or death over three years. But it's a single study, other scientists formally challenged whether the plastic measurement was contamination, and even its authors say it doesn't prove the plastic caused the harm. Nothing has replicated it yet."}, "scored": true, "evidence_caveats": ["rests essentially on one contested observational study (Marfella 2024); no independent replication located", "fast-moving: Re-search for independent replications of Marfella 2024 before any republish \u2014 this leaf rests on a single 2024 study and would move if it is replicated or refuted."]}, {"id": "n_health_cause", "parent_id": "n_health", "evidence_quality": "well-evidenced", "label": "Does controlled evidence show microplastics cause biological harm at doses relevant to real human exposure?", "children": [], "role": "leaf", "question": {"research": "Does controlled (animal / in-vitro) evidence show microplastics cause biological harm at doses relevant to real human exposure?", "simple": "Do experiments show microplastics cause harm at the amounts people actually get?"}, "claim_evaluated": {"research": "Controlled animal and in-vitro evidence shows microplastics cause biological harm (inflammation, oxidative stress, organ or reproductive effects) at doses relevant to real human exposure.", "simple": "Lab experiments show microplastics cause real biological harm at the kinds of amounts people are actually exposed to."}, "depends_on": {"research": "Two parts that must not be conflated: whether controlled models show harm at ALL (they frequently do \u2014 inflammation, oxidative stress, gut and reproductive effects), and whether they show it at REALISTIC doses (mostly they do not). A meta-analysis found only ~17% of tested exposure concentrations occur in the real environment; nanoplastic doses in studies run orders of magnitude above estimated human intake. Weight-of-evidence reviews (SAPEA 2019; WHO 2019) conclude harm at current human exposure has not been demonstrated. So a real effect at a high dose does not license a claim about everyday exposure.", "simple": "Split it in two: do experiments ever show harm (yes, often), and do they show it at real-life amounts (mostly no). Most studies use far more plastic than anyone actually encounters \u2014 one review found only about 17% of the amounts tested even occur in nature. Expert reviews say harm at today's real exposure levels hasn't been shown. Harm at a huge dose doesn't prove harm at a tiny one."}, "scored": true, "evidence_caveats": ["controlled harm is largely demonstrated at doses far above real human exposure \u2014 'harm at a realistic dose' is the contested part", "many studies use uniform polystyrene microspheres, unlike environmental particles"]}, {"id": "n_environ", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "Do microplastics harm the environment?", "children": ["n_environ_wildlife"], "role": "dimension", "question": {"research": "Do microplastics measurably harm wild organisms at the concentrations actually found in the environment?", "simple": "Are microplastics hurting wildlife?"}, "depends_on": {"research": "The ecological evidence base is larger and older than the human-health one, but it shares the dose problem: many demonstrated effects occur only at concentrations well above those measured in most of the environment. So the question is not merely 'can microplastics harm organisms' (they can, in the lab) but whether harm occurs at environmentally realistic concentrations, and whether risk is widespread or concentrated in pollution hotspots.", "simple": "There's more evidence on wildlife than on people, but the same catch applies: a lot of the proven harm happens only at concentrations higher than what's usually out there. So the real question isn't whether microplastics CAN hurt an animal in a tank \u2014 it's whether they do at the levels actually in rivers and seas, and whether that's everywhere or just in the dirtiest spots."}, "coverage_note": "Covers harm to aquatic (marine and freshwater) organisms at realistic concentrations, the best-studied ecological compartment. Terrestrial/soil ecosystems, whole-ecosystem and food-web effects, and macroplastic entanglement/ingestion are out of scope except where a finding carries them.", "scored": false, "evidence_caveats": ["the ecological evidence base is larger than the human one but shares the concentration-realism problem"]}, {"id": "n_environ_wildlife", "parent_id": "n_environ", "evidence_quality": "well-evidenced", "label": "Do microplastics cause measurable harm to aquatic organisms at environmentally realistic concentrations?", "children": [], "role": "leaf", "question": {"research": "Do microplastics cause measurable harm to aquatic organisms at environmentally realistic concentrations?", "simple": "Do microplastics harm water animals at the levels actually found in nature?"}, "claim_evaluated": {"research": "Microplastics cause measurable harm to aquatic organisms (reduced feeding, growth, reproduction, or survival) at concentrations actually found in the environment \u2014 not only at inflated laboratory doses.", "simple": "Microplastics measurably harm water animals at the amounts really present in the environment, not just at extreme lab doses."}, "depends_on": {"research": "Depends on reconciling meta-analytic evidence of real organismal effects (reduced consumption, growth, reproduction, survival across taxa) with the finding that most of those effects were measured at unrealistically high concentrations, and with risk-assessment work (species-sensitivity distributions) suggesting modelled thresholds are exceeded only in a minority of sampled locations. Effects are real and variable across taxa; whether they bite at today's ambient concentrations, and where, is the contested part.", "simple": "You have to weigh two things: studies pooling many experiments do find real harm (less eating, slower growth, fewer offspring, more death), but most of that harm showed up only at high test doses \u2014 and risk models suggest the danger level is passed only in a minority of places sampled. The harm is real; whether it happens at everyday environmental levels, and where, is what's disputed."}, "scored": true, "evidence_caveats": ["demonstrated effects are common but mostly at concentrations above ambient; harm at environmentally realistic concentrations is the contested part"]}, {"id": "n_policy", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "What would microplastic policy measurably change?", "children": ["n_policy_bans"], "role": "dimension", "question": {"research": "What would microplastic policy \u2014 source bans such as microbead bans \u2014 measurably change?", "simple": "Would microplastic bans actually do anything?"}, "depends_on": {"research": "Depends on matching the instrument to the target. A ban on a specific, controllable primary source (cosmetic microbeads) can remove that source \u2014 but whether it measurably reduces TOTAL microplastic pollution depends on how large a share that source was. Personal-care microbeads are a small fraction of primary microplastics, which are themselves a minority of environmental plastic dominated by secondary fragmentation and tyre/textile inputs the ban does not touch. So 'the ban removed its target' and 'the ban reduced microplastic pollution' are different claims.", "simple": "It depends on matching the rule to the problem. Banning cosmetic microbeads can wipe out microbeads \u2014 but those were only a tiny slice of all microplastics, which are mostly bits of larger plastic and tyre and clothing debris the ban doesn't affect. 'The ban got rid of microbeads' is not the same as 'the ban cut microplastic pollution'."}, "coverage_note": "Covers whether source-targeting bans measurably reduce pollution, using cosmetic-microbead bans as the worked case. Broader instruments (extended producer responsibility, tyre/textile regulation, wastewater capture, the global plastics treaty) are visible only where a cited finding carries them, and whether any such policy is JUSTIFIED on cost/benefit grounds is a values question outside this map.", "scored": false, "evidence_caveats": ["a source ban's effect on TOTAL pollution depends on the target's share of the total \u2014 a small target caps the achievable reduction"]}, {"id": "n_policy_bans", "parent_id": "n_policy", "evidence_quality": "well-evidenced", "label": "Do source-targeting policies such as microbead bans measurably reduce microplastic pollution?", "children": [], "role": "leaf", "question": {"research": "Do source-targeting policies such as microbead bans measurably reduce microplastic pollution?", "simple": "Do bans like the microbead ban actually cut microplastic pollution?"}, "claim_evaluated": {"research": "Source-targeting policies such as cosmetic-microbead bans measurably reduce microplastic pollution.", "simple": "Banning microplastic sources, like the ban on microbeads in cosmetics, measurably reduces microplastic pollution.", "_note": null}, "depends_on": {"research": "Depends on the outcome measured and the target's size. Microbead bans plausibly eliminate their targeted input, but that input (personal-care microbeads \u2248 2% of primary microplastics) is a small share of a total dominated by secondary fragmentation and tyre/textile wear. So a ban can succeed on its own terms while barely moving total pollution \u2014 a transportability gap between 'reduced the targeted source' and 'reduced microplastic pollution'. A directly-measured before/after reduction attributable to a ban was the weaker part of the evidence at authoring time.", "simple": "It depends what you measure and how big the target was. A microbead ban can remove microbeads \u2014 but microbeads were only about 2% of the deliberately-made microplastics, and those are a small part of the total, most of which comes from larger plastic breaking down and from tyres and clothes. So the ban can work on paper yet barely dent the overall problem. And hard before-and-after measurements of a ban actually lowering pollution were thin."}, "scored": true, "evidence_caveats": ["the measured reduction is of the TARGETED source (cosmetic microbeads \u2248 2% of primary microplastics), not of total microplastic pollution", "fast-moving: Re-run the EU intentionally-added-microplastic restriction (2023) and UN global plastics treaty search before any republish \u2014 the policy landscape was moving at authoring time."]}], "findings": [{"finding_id": "F-root-1", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "There is no single measurement of 'are microplastics harming us'. The literature separately measures whether concentrations can be measured reproducibly, whether particles are genuinely inside the body, where they originate, whether human burden is associated with disease, whether controlled models show harm at realistic doses, and whether wild organisms are harmed at realistic concentrations. Authoritative weight-of-evidence reviews conclude that, at current environmental concentrations, widespread population-level human harm has not been demonstrated \u2014 while stressing large uncertainties and the need for long-term monitoring. Presence is far better established than harm.", "simple": "No single study measures 'are microplastics harming us'. Researchers ask separate questions \u2014 can we measure them, are they really in our bodies, where do they come from, do people with more of them get sicker, do experiments show harm at real-world amounts, do they hurt wildlife. Expert reviews say that at today's levels, harm to the population hasn't been shown, though they stress how much is still unknown. That the particles are everywhere is much better established than that they hurt us."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "report", "source_citation": "SAPEA 2019, A Scientific Perspective on Microplastics in Nature and Society, Science Advice for Policy by European Academies.", "triggers_split_to": ["n_measure", "n_origin", "n_health", "n_environ", "n_policy"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "sapea", "caveat": {"research": "A weight-of-evidence synthesis: 'no demonstrated widespread harm' is a statement about current evidence and exposure, not a finding of safety; the report emphasises major knowledge gaps.", "simple": "'No proven widespread harm yet' is not the same as 'proven safe' \u2014 the same report stresses how much we still don't know."}}, {"finding_id": "F-root-2", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "Confidence is unevenly earned across the sub-questions, and the weakest link is measurement. A 2025 interlaboratory comparison across 84 laboratories found microplastic quantification reproducibility spanning roughly 46\u2013129% depending on polymer and method \u2014 so a reported concentration is partly an artefact of which lab and technique produced it. Every downstream exposure and association number inherits that error; confidence earned on a well-studied sub-question does not transfer to the others.", "simple": "We know some parts far better than others, and the shakiest is measurement itself. When 84 labs measured shared samples, their answers varied enormously depending on the method used. Since every exposure and health number is built on such measurements, being sure about one part of this topic doesn't make you right about the rest."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Ciornii et al. 2025, Interlaboratory Comparison Reveals State of the Art in Microplastic Detection and Quantification Methods, Analytical Chemistry 97:8719.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "interlab-vamas", "caveat": {"research": "A single (large) interlaboratory exercise on a defined matrix; it measures method reproducibility, not the truth of any one environmental concentration.", "simple": "One big cross-lab test on a set matrix \u2014 it shows methods disagree, not what the 'right' number is."}}, {"finding_id": "F-meas-1", "node_id": "n_measure", "direction": "COMPLICATES", "claim_paragraph": {"research": "This dimension has two distinct failure modes that must not be conflated. Measurement can be UNRELIABLE (different laboratories analysing the same sample report very different concentrations) or CONTAMINATED (a detection inside a tissue is real-looking but introduced by ubiquitous laboratory plastic). They are separate questions with separate evidence: a method can be irreproducible across labs yet still detect something real, and a detection can be genuine yet its concentration wrong.", "simple": "Two different ways the measurements could be shaky. One: labs disagree on the amount (unreliable). Two: the plastic a study finds in tissue actually came from the lab, not the body (contamination). These are separate problems \u2014 a lab can be inconsistent yet still find something real, or find something real but get the amount wrong."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Systematic review of microplastics and nanoplastics in human tissues: evidence, analytical protocols, and methodological challenges, 2026 (ScienceDirect S2666831926000081).", "triggers_split_to": ["n_measure_reliable", "n_measure_body"], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "contamination-review", "caveat": {"research": "A framing of the two failure modes drawn from the methodological literature, not a single measurement.", "simple": "A point about the two ways measurements fail, not one new study."}}, {"finding_id": "F-rel-1", "node_id": "n_measure_reliable", "direction": "CHALLENGES", "claim_paragraph": {"research": "A prestandardisation interlaboratory comparison organised under VAMAS had 84 laboratories worldwide analyse shared material by five methods (two thermo-analytical, three spectroscopic). Between-laboratory reproducibility spanned roughly 62\u2013117% (polyethylene) and 46\u201362% (PET) for thermo-analytical methods and 121\u2013129% / 64\u201370% for spectroscopic methods \u2014 i.e. the answer depends heavily on the laboratory, size threshold, and technique. The authors call for urgent harmonisation of methodology and standard operating procedures.", "simple": "In a global test, 84 labs measured the same material using five methods \u2014 and their results were far apart, varying by tens of percent depending on the technique. The scientists concluded there is an urgent need to standardise how microplastics are measured. If labs can't agree on the amount, numbers built on those measurements are hard to trust."}, "effect_size": {"research": "reproducibility ~46\u2013129% across polymers/methods; 84 labs", "simple": "results varied by tens of percent between labs"}, "source_type": "single-study", "source_citation": "Ciornii et al. 2025, Interlaboratory Comparison Reveals State of the Art in Microplastic Detection and Quantification Methods, Analytical Chemistry 97:8719.", "triggers_split_to": [], "tension_with": ["F-assoc-1", "F-body-1"], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "interlab-vamas", "caveat": {"research": "One (large) interlaboratory exercise on a water-soluble matrix; some methods performed better than others, so the failure is uneven rather than total.", "simple": "One big cross-lab test on a set matrix; some methods did better than others, so it's not that every measurement is useless \u2014 but agreement is poor."}}, {"finding_id": "F-rel-2", "node_id": "n_measure_reliable", "direction": "COMPLICATES", "claim_paragraph": {"research": "Standardisation efforts are advancing \u2014 reference materials, ring-trial designs, and ISO/ASTM method development aim to make microplastic quantification comparable across laboratories. But this work builds the machinery to ACHIEVE reproducibility; it does not yet demonstrate that cross-laboratory consistency has been attained. No located source rebuts the interlaboratory-comparison figures with a competing demonstration of achieved reproducibility, so the 'yes, measurement is consistent' direction of this leaf carries no independent evidence.", "simple": "Scientists are working hard to fix this \u2014 building reference materials and standard methods so labs can match each other. But that's building the tools to get there, not proof they've arrived. Nobody has shown labs now actually agree, so there's really no evidence on the 'yes, it's reliable' side yet."}, "effect_size": {"research": "qualitative; standardisation underway, achieved reproducibility not demonstrated", "simple": "still being fixed, not yet fixed"}, "source_type": "report", "source_citation": "e.g. Innovative reference materials for method validation in microplastic analysis including interlaboratory comparison exercises (2023, PMC10285000); ISO/ASTM microplastic method development.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "standardisation", "caveat": {"research": "Describes the standardisation process, not an achieved-reproducibility result \u2014 the FOR side of this leaf carries no independent evidence, so the leaf is effectively one-sided.", "simple": "This is about the effort to fix measurement, not proof it's fixed \u2014 so the 'reliable' side has no real evidence behind it yet."}}, {"finding_id": "F-body-1", "node_id": "n_measure_body", "direction": "SUPPORTS", "claim_paragraph": {"research": "Using a validated double-shot pyrolysis\u2013GC/MS method for particles \u2265700 nm, plastic was quantified in the whole blood of 17 of 22 healthy donors (~77%), at a mean summed concentration of 1.6 \u00b5g/mL; PET, polyethylene, polymers of styrene, and PMMA were the most common. This was the first mass-based quantification of the polymeric component of plastic in human blood, indicating that particles reach the systemic circulation.", "simple": "Using a carefully built method, scientists found and measured plastic in the blood of 17 of 22 healthy people (about 77%), averaging 1.6 micrograms per millilitre \u2014 mostly the plastics used in bottles, packaging, and foam. It was the first real measurement of plastic circulating in human blood, suggesting particles do get into the bloodstream."}, "effect_size": {"research": "quantifiable plastic in 17/22 donors; mean 1.6 \u00b5g/mL", "simple": "plastic in 17 of 22 people's blood, ~1.6 \u00b5g/mL"}, "source_type": "single-study", "source_citation": "Leslie et al. 2022, Discovery and quantification of plastic particle pollution in human blood, Environment International 163:107199.", "triggers_split_to": [], "tension_with": ["F-cause-1", "F-rel-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "blood-leslie", "caveat": {"research": "Small n (22); a first-of-kind method; like all such studies, background plastic contamination is a standing concern the authors worked to control but cannot fully exclude.", "simple": "Only 22 people, and a brand-new method; stray lab plastic is always a worry in these studies, though the team tried hard to rule it out."}}, {"finding_id": "F-body-2", "node_id": "n_measure_body", "direction": "SUPPORTS", "claim_paragraph": {"research": "Raman microspectroscopy of six human placentas from physiological pregnancies detected 12 microplastic fragments (5\u201310 \u00b5m) in four of the six \u2014 on the fetal side, the maternal side, and the chorioamniotic membranes. All were pigmented; three were identified as stained polypropylene. This was the first report of microplastics in the human placenta, a second independent tissue and team supporting genuine internal presence.", "simple": "Looking at six human placentas, researchers found 12 tiny plastic fragments in four of them \u2014 on both the baby's and mother's side. It was the first time microplastics were found in the placenta, and it's a different tissue and team from the blood study, both pointing to real presence in the body."}, "effect_size": {"research": "12 fragments (5\u201310 \u00b5m) in 4 of 6 placentas", "simple": "plastic fragments in 4 of 6 placentas"}, "source_type": "single-study", "source_citation": "Ragusa et al. 2021, Plasticenta: First evidence of microplastics in human placenta, Environment International 146:106274.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "observational", "source_cluster": "placenta-ragusa", "caveat": {"research": "Very small pilot (6 placentas); only a fraction of each was analysed; contamination controls were limited \u2014 a discovery study, not a prevalence estimate.", "simple": "A tiny pilot of six placentas, only part of each checked, with limited contamination checks \u2014 a first sighting, not a measure of how common it is."}}, {"finding_id": "F-body-3", "node_id": "n_measure_body", "direction": "CHALLENGES", "claim_paragraph": {"research": "Because plastics pervade laboratory air, clothing, and labware, human-tissue detections are vulnerable to false positives: methodological reviews find that failing to run and report procedural blanks leads to overestimation, that tissue lipids and proteins are known false positives for plastic, and that stain-based methods (e.g. Nile Red) mark non-plastic organic matter. Notably, studies that added rigorous multi-blank controls \u2014 mostly after 2023 \u2014 generally reported LOWER, more realistic concentrations, implying part of the earlier signal was contamination.", "simple": "Plastic is everywhere in a lab \u2014 in the air, on clothes, in the equipment \u2014 so 'finding' it in tissue is easy to get wrong. Reviews show that studies which skipped clean 'blank' checks overestimated, that fat and protein in tissue can be mistaken for plastic, and that some stains light up non-plastic material. Tellingly, the careful recent studies that ran proper checks tend to find LESS \u2014 so some of the earlier plastic was probably contamination."}, "effect_size": {"research": "qualitative; rigorous-blank studies report lower concentrations", "simple": "careful studies find less"}, "source_type": "systematic-review", "source_citation": "Systematic review of microplastics and nanoplastics in human tissues: evidence, analytical protocols, and methodological challenges, 2026 (ScienceDirect S2666831926000081); analytical-challenges reviews.", "triggers_split_to": [], "tension_with": ["F-assoc-1"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "contamination-review", "caveat": {"research": "A methodological critique, not a claim that no microplastics are present in the body; it argues that concentrations are overstated and some detections artefactual, not that the phenomenon is zero.", "simple": "This says the amounts are overstated and some 'finds' are false \u2014 not that there's no plastic in the body at all."}}, {"finding_id": "F-orig-1", "node_id": "n_origin", "direction": "COMPLICATES", "claim_paragraph": {"research": "That microplastics are human-made is not in dispute; the live questions are which sources dominate, how confidently they are quantified, and whether the environmentally dominant fraction can be attributed at all. Source-apportionment inventories cover PRIMARY microplastics (deliberately made, or worn from products) but the most abundant environmental microplastic is SECONDARY \u2014 fragments of larger mismanaged plastic waste \u2014 which is poorly quantified. So 'we know where they come from' is stronger for naming and ranking primary sources than for quantifying the total.", "simple": "Nobody argues microplastics are natural. The real questions are which sources are biggest, how sure the numbers are, and whether we can even track the largest kind. Studies can add up the deliberately-made small plastics (tyres, fibres, beads), but most environmental microplastic is bits breaking off bigger plastic litter, which is hard to measure. Naming the sources is easier than pinning down the total."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "report", "source_citation": "Boucher & Friot 2017, IUCN (primary vs secondary framing); microplastic source-apportionment literature.", "triggers_split_to": ["n_origin_sources"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "secondary-dominance", "caveat": {"research": "A framing of the primary/secondary distinction and its measurement asymmetry, not a standalone measurement.", "simple": "A point about the two kinds of microplastic and which is easier to measure, not a new study."}}, {"finding_id": "F-src-1", "node_id": "n_origin_sources", "direction": "SUPPORTS", "claim_paragraph": {"research": "A global source evaluation estimated that primary microplastics are 15\u201331% of the plastic entering oceans, with a small set of dominant, actionable sources: synthetic-textile laundering (~35% of primary microplastics) and tyre abrasion (~28%) together account for roughly two-thirds, followed by city dust, road markings, marine coatings, plastic pellets, and personal-care microbeads. The dominant contributors are identified and ranked well enough to point interventions at the biggest primary sources.", "simple": "A global study estimated that deliberately-made or worn-off microplastics are 15\u201331% of ocean plastic, and that just two sources \u2014 washing synthetic clothes (~35%) and tyre wear (~28%) \u2014 make up about two-thirds of them, with road dust, paint, pellets, and cosmetic beads behind. So for these sources, we know the biggest culprits well enough to aim policy at them."}, "effect_size": {"research": "primary MP = 15\u201331% of ocean plastic; textiles ~35%, tyres ~28% of primary", "simple": "clothes ~35% and tyres ~28% of the deliberately-made microplastics"}, "source_type": "report", "source_citation": "Boucher & Friot 2017, Primary Microplastics in the Oceans: A Global Evaluation of Sources, IUCN, Gland.", "triggers_split_to": [], "tension_with": ["F-ban-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "boucher-friot", "caveat": {"research": "A modelled global apportionment with wide uncertainty ranges; it addresses PRIMARY microplastics (15\u201331% of the total), not the larger secondary fraction; regional shares differ (textiles dominate in Asia, tyres in the Americas/Europe).", "simple": "A global estimate with big uncertainty, and only about the deliberately-made kind (15\u201331% of the total) \u2014 not the larger amount from plastic breaking down."}}, {"finding_id": "F-src-2", "node_id": "n_origin_sources", "direction": "CHALLENGES", "claim_paragraph": {"research": "The claim strains at the level of the TOTAL. Primary-source inventories cover only the 15\u201331% of environmental plastic that is primary; the majority is secondary microplastic from the fragmentation of larger mismanaged waste, whose contributing sources cannot be attributed with confidence and whose formation is diffuse across time and place. Primary estimates themselves carry order-of-magnitude uncertainty and are model-dependent. So the biggest contributors to total microplastic pollution are NOT quantified well enough to target with confidence.", "simple": "The problem is the total. The neat source rankings only cover the deliberately-made 15\u201331%; most microplastic is bits breaking off larger plastic litter, and you can't trace which product or place those came from. Even the primary estimates swing wildly depending on the model. So for microplastic pollution as a whole, we don't actually know the biggest contributors well enough to target them confidently."}, "effect_size": {"research": "secondary (unattributed) fraction dominates; primary is only 15\u201331%", "simple": "most microplastic is untraceable fragments; the rankings cover only a slice"}, "source_type": "report", "source_citation": "Boucher & Friot 2017, IUCN (primary = 15\u201331% of total); microplastic source-apportionment reviews on secondary-fragment dominance.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "secondary-dominance", "caveat": {"research": "This is a scope-and-uncertainty argument about the total, not a claim that no sources are known; the primary-source rankings themselves are not disputed for the primary fraction.", "simple": "This is about not being able to trace the whole problem \u2014 not a claim that we know nothing; the rankings for the deliberately-made kind still stand."}}, {"finding_id": "F-health-1", "node_id": "n_health", "direction": "COMPLICATES", "claim_paragraph": {"research": "Two separable questions govern this dimension, and both are weak. Whether human burden is ASSOCIATED with disease rests on observational human studies \u2014 currently essentially one contested study. Whether microplastics CAUSE harm rests on animal and in-vitro models where the pivotal problem is dose. Crucially, neither finding a particle in a tissue nor demonstrating harm at a high laboratory dose establishes harm at the amounts people actually encounter \u2014 the presence-to-harm and high-dose-to-real-dose steps are where the evidence is thinnest.", "simple": "Two separate, weak questions. One: do people with more microplastics get sicker? Almost the only human study on this is disputed. Two: do experiments prove harm? They often do \u2014 but usually at doses far above real life. And finding a particle in the body, or harm at a huge lab dose, is not the same as harm at the tiny amounts people actually get. Those two leaps are where the evidence is weakest."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "report", "source_citation": "SAPEA 2019 (weight-of-evidence on human health); WHO 2019, Microplastics in drinking-water.", "triggers_split_to": ["n_health_assoc", "n_health_cause"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "sapea", "caveat": {"research": "A framing of the two health questions and the two inferential gaps, not a measurement.", "simple": "A point about the two health questions and where they break down, not a new study."}}, {"finding_id": "F-assoc-1", "node_id": "n_health_assoc", "direction": "SUPPORTS", "claim_paragraph": {"research": "In a prospective, multicentre observational study of 257 patients undergoing carotid endarterectomy, micro- and nanoplastics were detected in plaque of most patients (polyethylene in 58.4%, mean 21.7\u00b124.5 \u00b5g/mg; PVC in 12.1%). Over a mean 34 months, patients with detectable plastics had a hazard ratio of 4.53 (95% CI 2.00\u201310.27) for the composite of myocardial infarction, stroke, or death from any cause \u2014 the first human study linking measured microplastic burden to hard cardiovascular outcomes.", "simple": "In a study of 257 people having plaque removed from a neck artery, most had microplastics in that plaque. Over about three years, those with detectable plastic were about 4.5 times as likely to have a heart attack, stroke, or die as those without. It was the first human study tying a measured amount of microplastic to serious heart outcomes."}, "effect_size": {"research": "HR 4.53 (95% CI 2.00\u201310.27) for MI/stroke/death; MNPs in 58.4%", "simple": "~4.5\u00d7 the rate of heart attack, stroke, or death"}, "source_type": "single-study", "source_citation": "Marfella et al. 2024, Microplastics and Nanoplastics in Atheromas and Cardiovascular Events, New England Journal of Medicine 390:900\u2013910.", "triggers_split_to": [], "tension_with": ["F-body-3", "F-cause-1", "F-rel-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "marfella-nejm", "caveat": {"research": "Observational and single-population (carotid-endarterectomy patients); the authors state it does not prove causation and unmeasured confounding is possible; the exposure measurement drew formal contamination critiques (see F-assoc-2).", "simple": "It's a single study in one kind of patient; the authors say it doesn't prove the plastic caused the harm, and others challenged whether the plastic reading was contamination."}}, {"finding_id": "F-assoc-2", "node_id": "n_health_assoc", "direction": "CHALLENGES", "claim_paragraph": {"research": "Formal correspondence in the same journal challenged whether the plaque microplastic measurement is credible: no pre-analytical anti-contamination procedures beyond glass tubes were described, the operating-room environment and surgical equipment themselves contain polyethylene and PVC (creating high intraoperative contamination risk), and no operating-room blank samples were tested. If the exposure classification is contaminated, the reported association between 'plastic-positive' plaque and cardiovascular events could be an artefact of measurement rather than a real biological signal.", "simple": "Other scientists formally challenged the study in the same journal: it didn't describe proper steps to keep stray plastic out, the operating room and its equipment are full of the very plastics measured, and no 'blank' control samples were taken from the room. If the plastic reading is contamination, the link to heart problems could be a measurement artefact, not a real effect."}, "effect_size": {"research": "qualitative; contamination-control critique", "simple": "the plastic reading may be contamination"}, "source_type": "correspondence", "source_citation": "Correspondence on Marfella et al., New England Journal of Medicine 390:1770\u20131772 (9 May 2024, NEJMc2404154), and authors' reply.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "marfella-critique", "caveat": {"research": "A methodological critique, not a competing study; the authors replied defending their controls. It raises reasonable doubt about the exposure measurement, it does not disprove the association.", "simple": "This is a criticism, not a rival study, and the authors pushed back \u2014 it raises doubt about the measurement rather than disproving the link."}}, {"finding_id": "F-assoc-3", "node_id": "n_health_assoc", "direction": "COMPLICATES", "claim_paragraph": {"research": "The broader human evidence base is essentially this one study: there is no replication in an independent population, and authoritative weight-of-evidence reviews (SAPEA 2019; WHO 2019) conclude that a population-level human health effect of microplastics has not been demonstrated at current exposures. A single striking observational association, however large the hazard ratio, cannot on its own carry a general claim that microplastic burden is associated with worse health.", "simple": "Beyond that one study there's almost nothing: no independent study has repeated it, and major expert reviews say a population-wide health effect from microplastics hasn't been shown at today's exposure levels. One dramatic result, however big the number, can't by itself establish that people with more microplastics have worse health."}, "effect_size": {"research": "qualitative; no independent replication located", "simple": "qualitative; not yet replicated"}, "source_type": "report", "source_citation": "WHO 2019, Microplastics in drinking-water; SAPEA 2019 (human-health weight of evidence).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "who", "caveat": {"research": "'Not demonstrated' reflects sparse and recent evidence plus the measurement problem; it is not a finding that no association exists. Both these reviews predate the 2024 Marfella study.", "simple": "'Not shown' reflects how little and how new the evidence is \u2014 not proof there's no link. These reviews also came out before the 2024 heart study."}}, {"finding_id": "F-cause-1", "node_id": "n_health_cause", "direction": "SUPPORTS", "claim_paragraph": {"research": "Controlled animal and in-vitro studies repeatedly demonstrate that microplastics and nanoplastics CAN cause biological harm: reviews of toxicological pathways report inflammation, oxidative stress, and gut, metabolic, and reproductive effects across rodent and cellular models. Mechanistically, small enough particles translocate across biological barriers and provoke immune and oxidative responses \u2014 establishing biological plausibility that microplastics are not inert.", "simple": "Lab experiments in animals and cells repeatedly show microplastics CAN do biological damage \u2014 inflammation, oxidative stress, and effects on the gut, metabolism, and reproduction. Small enough particles can cross into tissues and trigger immune reactions. So it's biologically plausible that microplastics aren't harmless."}, "effect_size": {"research": "qualitative; harm demonstrated across models (mostly high-dose)", "simple": "harm shown in lab models (mostly at high doses)"}, "source_type": "systematic-review", "source_citation": "Exploring toxicological pathways of microplastics and nanoplastics: insights from animal and cellular models, Journal of Hazardous Materials 2025 (S0304389425007095).", "triggers_split_to": [], "tension_with": ["F-assoc-1", "F-body-1", "F-cause-2", "F-cause-3"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "tox-review", "caveat": {"research": "Load-bearing limitation: the MAJORITY of these effects are demonstrated at doses/concentrations well above real human exposure, and often with uniform polystyrene microspheres unlike environmental particles \u2014 so this shows harm is POSSIBLE, not that it occurs at realistic doses (see F-cause-2, F-cause-3).", "simple": "The catch: most of this harm was shown at doses far higher than anyone actually gets, often using lab-made beads unlike real-world plastic \u2014 so it shows harm is possible, not that it happens at real-life amounts."}}, {"finding_id": "F-cause-2", "node_id": "n_health_cause", "direction": "CHALLENGES", "claim_paragraph": {"research": "The controlled evidence overwhelmingly uses unrealistic doses. Reviews focused on 'dose' find that experimental exposures run orders of magnitude above estimated real human intake (nanogram-to-microgram per kg per day), and a meta-analysis of the plastic-effects literature found only ~17% of tested concentrations were environmentally relevant. Effects demonstrated at inflated doses do not license a claim about everyday exposure; at realistic doses, controlled harm is largely undemonstrated.", "simple": "Almost all these experiments use far too much plastic. Reviews find the doses tested are hundreds to thousands of times higher than what people really get, and one big analysis found only about 17% of tested amounts even occur in nature. Harm at a huge dose doesn't prove harm at a tiny one \u2014 and at realistic amounts, the experiments mostly haven't shown harm."}, "effect_size": {"research": "only ~17% of tested concentrations environmentally relevant; doses orders of magnitude high", "simple": "only ~17% of tested amounts are realistic"}, "source_type": "systematic-review", "source_citation": "Micro/nanoplastics effects on organisms: a review focusing on 'dose', Journal of Hazardous Materials 2021 (S0304389421010487); Bucci et al. 2020, Ecological Applications 30(2):e02044 (17% figure).", "triggers_split_to": [], "tension_with": ["F-cause-1", "F-wild-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "dose-critique", "caveat": {"research": "'Undemonstrated at realistic dose' is not proof of safety at realistic dose \u2014 it reflects that the experiments were not designed to test realistic exposure, and low-dose chronic effects remain possible.", "simple": "'Not shown at real amounts' isn't 'proven safe at real amounts' \u2014 the experiments just weren't set up to test everyday exposure, and slow low-dose effects are still possible."}}, {"finding_id": "F-cause-3", "node_id": "n_health_cause", "direction": "CHALLENGES", "claim_paragraph": {"research": "Independent weight-of-evidence bodies reach the same verdict. SAPEA (2019) concluded that, on the best available evidence, microplastics do not appear to pose a widespread risk to human health at current exposure levels, while stressing uncertainty; WHO (2019) judged the health concern from microplastics in drinking water to be low on available evidence, noting particles >150 \u00b5m are not absorbed and data on nanoplastics are insufficient. Two authoritative reviews, reading the controlled and exposure literature, decline to affirm harm at real exposure.", "simple": "Two big expert bodies agree. A European science-academies review (2019) said microplastics don't appear to pose a widespread health risk at current levels, while stressing the unknowns; the WHO (2019) called the health concern from microplastics in drinking water low, noting bigger particles aren't absorbed and there's too little data on the tiniest ones. Reading the same experiments, both declined to say harm happens at real exposure."}, "effect_size": {"research": "qualitative; no widespread risk demonstrated at current exposure", "simple": "expert bodies: no widespread risk shown at current levels"}, "source_type": "report", "source_citation": "SAPEA 2019, A Scientific Perspective on Microplastics in Nature and Society; WHO 2019, Microplastics in drinking-water.", "triggers_split_to": [], "tension_with": ["F-cause-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "sapea", "caveat": {"research": "Both reviews explicitly frame their conclusions as provisional given major data gaps and the measurement problem, and both predate the most recent human and animal studies; 'no demonstrated risk' is not 'demonstrated no risk'.", "simple": "Both reviews call their conclusions provisional given big gaps, and both predate the newest studies; 'no proven risk' isn't 'proven no risk'."}}, {"finding_id": "F-env-1", "node_id": "n_environ", "direction": "COMPLICATES", "claim_paragraph": {"research": "The ecological evidence base is larger and older than the human-health one, but it inherits the same dose problem. Laboratory studies establish that microplastics CAN harm organisms, yet many demonstrated effects occur only at concentrations above those measured across most of the environment. So the ecological question is not 'can microplastics harm wildlife' (they can) but whether harm occurs at environmentally realistic concentrations, and whether risk is widespread or concentrated in pollution hotspots.", "simple": "There's more evidence on wildlife than on people, but the same catch applies: lab studies show microplastics CAN harm animals, but a lot of that harm shows up only at concentrations higher than what's usually out there. So the real question isn't whether they can hurt an animal in a tank \u2014 it's whether they do at the levels actually in rivers and seas, and whether that's everywhere or just in the worst spots."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "meta-analysis", "source_citation": "Bucci et al. 2020, Ecological Applications 30(2):e02044 (concentration-realism framing).", "triggers_split_to": ["n_environ_wildlife"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "bucci-rochman", "caveat": {"research": "A framing of the concentration-realism problem for ecology, not a standalone effect estimate.", "simple": "A point about testing at realistic amounts, not a new effect measurement."}}, {"finding_id": "F-wild-1", "node_id": "n_environ_wildlife", "direction": "SUPPORTS", "claim_paragraph": {"research": "A meta-analysis of microplastic effects on fish and aquatic invertebrates found negative effects on consumption, growth, reproduction, and survival for at least some taxa, with reduced consumption of natural prey the most consistent effect; zooplankton were flagged as particularly susceptible, with potential food-web ramifications. Real organismal harm from microplastic exposure is demonstrable, not merely hypothesised.", "simple": "A study pooling many experiments on fish and water invertebrates found real harm in at least some species \u2014 less feeding, slower growth, fewer offspring, more death \u2014 with eating less of their natural food the most consistent effect. Tiny animals like zooplankton looked especially vulnerable, which could ripple up the food chain. So the harm is real, not just a theory."}, "effect_size": {"research": "negative effects on consumption/growth/reproduction/survival (taxon-dependent); consumption most consistent", "simple": "less feeding, growth, reproduction, survival in some species"}, "source_type": "meta-analysis", "source_citation": "Foley et al. 2018, A meta-analysis of the effects of exposure to microplastics on fish and aquatic invertebrates, Science of the Total Environment 631\u2013632:550\u2013559.", "triggers_split_to": [], "tension_with": ["F-wild-2", "F-wild-3"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "foley-meta", "caveat": {"research": "The authors stress effects were 'highly variable across taxa' and many were neutral; the meta-analysis pools studies many of which used high exposure concentrations, so it establishes harm exists more than harm at ambient levels.", "simple": "The authors stress the effects varied a lot between species and many were neutral; and many pooled studies used high doses \u2014 so it shows harm exists more than harm at everyday levels."}}, {"finding_id": "F-wild-2", "node_id": "n_environ_wildlife", "direction": "CHALLENGES", "claim_paragraph": {"research": "A meta-analysis and systematic review of 139 studies testing 577 independent effects found that only ~17% of the exposure concentrations used were environmentally relevant \u2014 i.e. the great majority of demonstrated ecological effects occur at plastic concentrations higher than those found across most of the environment. The evidence that microplastics harm organisms AT REALISTIC CONCENTRATIONS is therefore much weaker than the raw count of 'effect found' studies implies.", "simple": "A review of 139 studies and 577 tested effects found only about 17% used amounts of plastic that actually occur in nature \u2014 so most of the proven harm happened at concentrations higher than what's really out there. That means the evidence for harm at REAL-WORLD levels is far thinner than the pile of 'we found an effect' studies suggests."}, "effect_size": {"research": "only ~17% of tested concentrations environmentally relevant (139 studies, 577 effects)", "simple": "only ~17% of tests used realistic amounts"}, "source_type": "meta-analysis", "source_citation": "Bucci, Tulio & Rochman 2020, What is known and unknown about the effects of plastic pollution: A meta-analysis and systematic review, Ecological Applications 30(2):e02044.", "triggers_split_to": [], "tension_with": ["F-cause-2", "F-wild-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "bucci-rochman", "caveat": {"research": "'Mostly tested at unrealistic concentrations' is a critique of the evidence base, not proof of no effect at ambient levels; the same review documents that effects are common when they are tested.", "simple": "'Mostly tested at unrealistic amounts' criticises the evidence, it doesn't prove there's no harm at real levels \u2014 and the same review found effects are common when tested."}}, {"finding_id": "F-wild-3", "node_id": "n_environ_wildlife", "direction": "CHALLENGES", "claim_paragraph": {"research": "A quality-screened risk assessment using species-sensitivity distributions (290 data points from 21 studies) derived a marine hazard concentration for 5% of species (HC5) of ~33.3 particles/L and estimated that modelled effect thresholds are currently exceeded at only ~17\u201332% of sampled locations. On this framework, ecological risk from microplastics is real but concentrated in pollution hotspots rather than ubiquitous at present ambient concentrations.", "simple": "A careful risk analysis, keeping only good-quality studies, estimated the level at which microplastics start to threaten sensitive species \u2014 and found that today's environmental concentrations pass that danger level in only about 17\u201332% of the places sampled. So the ecological risk is real but concentrated in the dirtiest hotspots, not everywhere yet."}, "effect_size": {"research": "marine HC5 ~33.3 particles/L; thresholds exceeded at ~17\u201332% of sites", "simple": "danger level passed in ~17\u201332% of sampled sites"}, "source_type": "systematic-review", "source_citation": "Koelmans et al. 2022, Risk-based management framework for microplastics in aquatic ecosystems, Microplastics and Nanoplastics 2:12.", "triggers_split_to": [], "tension_with": ["F-wild-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "koelmans-ssd", "caveat": {"research": "The HC5 confidence interval is very wide (0.36\u201313,943 particles/L), reflecting deep uncertainty; rising emissions and the smallest (nano) particles, poorly captured, could shift exceedance upward \u2014 'hotspots only' is a present-tense, uncertain estimate.", "simple": "The estimate has a huge uncertainty range, and rising pollution plus the tiniest particles (hard to measure) could push it higher \u2014 'hotspots only' is a shaky, for-now figure."}}, {"finding_id": "F-pol-1", "node_id": "n_policy", "direction": "COMPLICATES", "claim_paragraph": {"research": "The policy question turns on matching the instrument to the target. A ban on a specific, controllable primary source (cosmetic microbeads) can remove that source at source \u2014 but whether it measurably reduces TOTAL microplastic pollution depends on how large a share that source was. 'The ban removed its target' and 'the ban reduced microplastic pollution' are different claims, and the gap between them is set by the target's share of the total.", "simple": "It comes down to matching the rule to the problem. Banning cosmetic microbeads can wipe out microbeads \u2014 but whether that dents total microplastic pollution depends on how big a slice microbeads were. 'The ban got rid of microbeads' and 'the ban cut microplastic pollution' are two different claims, and the difference depends on how much of the total the target was."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "report", "source_citation": "Boucher & Friot 2017, IUCN (microbeads ~2% of primary microplastics).", "triggers_split_to": ["n_policy_bans"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "boucher-friot", "caveat": {"research": "A framing of the instrument-target match, not an outcome measurement.", "simple": "A point about matching the rule to the problem, not a measured result."}}, {"finding_id": "F-ban-1", "node_id": "n_policy_bans", "direction": "SUPPORTS", "claim_paragraph": {"research": "Source-targeting bans can measurably remove their target. Monitoring of Toronto wastewater-treatment-plant effluents (2016\u20132019) and Lake Ontario surface water (2015 vs 2018), spanning the US (2017) and Canadian (2018) cosmetic-microbead bans, found median polyethylene microbead concentrations in effluent declined by up to ~86% (from 8.4\u201314.3 to 2.0\u20132.2 particles/m\u00b3) after the bans \u2014 a first direct before/after demonstration that a microbead ban reduced the microbeads entering surface waters.", "simple": "Bans on a specific source can measurably wipe out that source. Monitoring of Toronto's treated wastewater and Lake Ontario before and after the US (2017) and Canadian (2018) microbead bans found microbeads in the treated water fell by up to about 86% afterwards \u2014 the first direct before-and-after proof that a microbead ban actually cut the microbeads reaching the water."}, "effect_size": {"research": "up to ~86% decline in effluent microbeads after the bans", "simple": "up to ~86% fewer microbeads in treated wastewater"}, "source_type": "single-study", "source_citation": "Dean et al. 2023, Reductions of Plastic Microbeads from Personal Care Products in Wastewater Effluents and Lake Waters Following Regulatory Actions, ACS ES&T Water (acsestwater.3c00526).", "triggers_split_to": [], "tension_with": ["F-ban-2"], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "microbead-ban", "caveat": {"research": "Measures the TARGETED input (cosmetic polyethylene microbeads) in one region, not total microplastic pollution; the sampling size-range misses smaller microbeads, and other microplastic sources were unaffected.", "simple": "It measures the banned microbeads in one region, not total microplastic pollution; the method also misses the smallest beads, and other sources kept going."}}, {"finding_id": "F-ban-2", "node_id": "n_policy_bans", "direction": "CHALLENGES", "claim_paragraph": {"research": "The targeted source is a tiny share of the problem. Personal-care microbeads are ~2% of PRIMARY microplastics, which are themselves only 15\u201331% of environmental plastic; the total is dominated by secondary fragmentation and by tyre and textile inputs that cosmetic-microbead bans do not touch. The source evaluation's own authors conclude that banning microbeads is 'an illustrative action' that 'will not solve the wider problem'. So a ban can succeed on its own terms while barely moving total microplastic pollution.", "simple": "The banned source is a sliver of the problem. Cosmetic microbeads are about 2% of the deliberately-made microplastics, which are themselves only 15\u201331% of the total \u2014 most of which comes from larger plastic breaking down and from tyres and clothes that the ban doesn't affect. The source study's own authors call banning microbeads 'illustrative' and say it 'will not solve the wider problem'. So the ban can work yet barely change total pollution."}, "effect_size": {"research": "microbeads ~2% of primary MP; primary is 15\u201331% of total", "simple": "microbeads ~2% of deliberately-made microplastics"}, "source_type": "report", "source_citation": "Boucher & Friot 2017, Primary Microplastics in the Oceans, IUCN (cosmetics ~2%; 'will not solve the wider problem').", "triggers_split_to": [], "tension_with": ["F-ban-1", "F-src-1"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "boucher-friot", "caveat": {"research": "This bounds what a microbead ban can achieve for the TOTAL; it is not an argument that source policy in general is futile \u2014 a ban on a larger source (tyres, textiles) would not face the same ceiling.", "simple": "This limits what a microbead ban can do for the total \u2014 not a claim that all bans are pointless; a ban on a bigger source (tyres, clothes) wouldn't hit the same ceiling."}}], "tensions": [{"a": "F-rel-1", "b": "F-assoc-1", "kind": "assumption-sensitivity", "note": {"research": "The cardiovascular association depends on a microplastic measurement, but the interlaboratory comparison shows such quantification is poorly reproducible across labs and methods. If the exposure ('plastic-positive' plaque and its \u00b5g/mg) is measured with large error, what the hazard ratio means depends on assuming the measurement was reliable.", "simple": "The heart-risk finding rests on measuring plastic in plaque \u2014 but labs can't reliably agree on such measurements. If the plastic reading is shaky, the meaning of the 4.5\u00d7 risk rests on assuming the measurement was sound."}}, {"a": "F-rel-1", "b": "F-body-1", "kind": "assumption-sensitivity", "note": {"research": "The blood study reports a mass concentration (1.6 \u00b5g/mL), but the interlaboratory comparison finds microplastic quantification varies by tens of percent between labs. The reported concentration is only as trustworthy as the reproducibility of the method that produced it.", "simple": "The blood study gives a precise-looking number (1.6 \u00b5g/mL), but labs disagree wildly on such measurements. The number is only as reliable as the method behind it."}}, {"a": "F-body-3", "b": "F-assoc-1", "kind": "cross-dimension", "note": {"research": "The contamination critique of human-tissue detection \u2014 labs are full of plastic, blanks are essential, tissue components mimic plastic \u2014 applies directly to the plaque microplastic measurement in the cardiovascular study. A measurement-validity problem in one dimension undercuts a harm claim in another.", "simple": "The warning that lab plastic contaminates tissue samples applies straight to the plaque measurement in the heart study. A measurement problem in one place weakens a harm claim elsewhere."}}, {"a": "F-cause-1", "b": "F-cause-2", "kind": "empirical-contradiction", "note": {"research": "Toxicology reviews show microplastics cause harm across animal and cellular models; the dose-realism critique shows the great majority of those effects were produced at concentrations far above real exposure. Harm-is-possible and harm-at-realistic-dose-is-undemonstrated pull directly against each other within this leaf.", "simple": "Lab studies show microplastics can cause harm; but most of that harm was produced at doses far higher than real life. 'It can hurt you' and 'it hasn't been shown to hurt you at real amounts' pull against each other."}}, {"a": "F-cause-1", "b": "F-cause-3", "kind": "empirical-contradiction", "note": {"research": "Individual toxicology studies demonstrate biological harm; the SAPEA/WHO weight-of-evidence syntheses, reading the same body of work, conclude harm at current human exposure is not demonstrated. The single-study signal and the pooled expert verdict point different ways.", "simple": "Single experiments show damage; the big expert reviews, reading all of them together, say harm at real exposure isn't proven. The individual studies and the overall verdict disagree."}}, {"a": "F-wild-1", "b": "F-wild-2", "kind": "empirical-contradiction", "note": {"research": "The Foley meta-analysis documents real organismal effects; the Bucci\u2013Rochman meta-analysis finds only ~17% of tested concentrations were environmentally relevant. Both are meta-analyses of the same field pointing opposite ways on whether the demonstrated harm bites at ambient concentrations.", "simple": "One pooled analysis finds real harm to animals; another finds only ~17% of the tests used realistic amounts. Same field, opposite messages on whether the harm happens at real-world levels."}}, {"a": "F-wild-1", "b": "F-wild-3", "kind": "assumption-sensitivity", "note": {"research": "Demonstrated organismal effects (Foley) and a risk model finding thresholds exceeded at only 17\u201332% of sites (Koelmans) are reconciled only by an assumption about which concentrations matter: harm is real in the lab, but whether it is realised in the field depends on comparing ambient concentrations to effect thresholds.", "simple": "Real lab harm and a risk model saying the danger level is passed in only 17\u201332% of places fit together only if you decide which concentrations count: harm is real in a tank, but whether it happens in the wild depends on comparing real levels to the danger line."}}, {"a": "F-src-1", "b": "F-ban-2", "kind": "scope-aggregation", "note": {"research": "The same source evaluation that ranks dominant primary sources (textiles ~35%, tyres ~28%) also puts cosmetic microbeads at ~2% \u2014 so the sources a microbead ban targets are precisely the small ones, while the ranked large sources go untouched. Naming the big sources and targeting them are pulled apart by which source the policy actually addresses.", "simple": "The same study that finds the big sources (clothes ~35%, tyres ~28%) puts cosmetic beads at ~2% \u2014 so a microbead ban hits the small source while the big ones it identified go untouched. Knowing the big sources isn't the same as targeting them."}}, {"a": "F-ban-1", "b": "F-ban-2", "kind": "scope-aggregation", "note": {"research": "The ban measurably cut its target (up to ~86% fewer microbeads in effluent) yet that target is ~2% of primary microplastics \u2014 so a real, measured success on the targeted source coexists with a negligible effect on total microplastic pollution. 'Reduced the target' and 'reduced pollution' are different scales.", "simple": "The ban really did cut microbeads (up to ~86%) \u2014 but microbeads were only ~2% of the deliberately-made microplastics, so a genuine win on the target barely moves the total. 'Cut the target' and 'cut pollution' are different sizes."}}, {"a": "F-cause-2", "b": "F-wild-2", "kind": "context-transportability", "note": {"research": "The same concentration-realism problem recurs in both the human-health and ecological leaves: most demonstrated effects \u2014 in mammalian models and in aquatic organisms alike \u2014 were produced at concentrations above those in most of the environment. The critique transports across the two harm dimensions.", "simple": "The same 'unrealistic amounts' problem shows up for both people and wildlife: most proven harm, in animals and in water creatures, came from doses higher than what's really out there. The same caution applies to both."}}, {"a": "F-body-1", "b": "F-cause-1", "kind": "assumption-sensitivity", "note": {"research": "That microplastics are detected in blood (presence) and that they cause harm in controlled models (mechanism) are often merged into 'plastic in your body is hurting you' \u2014 but presence in a tissue does not establish harm, and mechanistic harm at high dose does not establish that the detected body burden is doing damage. The link between the two is an assumption, not a finding.", "simple": "'There's plastic in my blood' and 'plastic causes harm in the lab' get merged into 'the plastic in me is hurting me' \u2014 but finding it in the body isn't proof it's doing damage, and lab harm at high doses isn't proof the amount in you matters. Joining the two is an assumption."}}, {"a": "F-assoc-1", "b": "F-cause-1", "kind": "assumption-sensitivity", "note": {"research": "An observational human association (Marfella) and controlled mechanistic harm (toxicology models) are different estimands: the first measures whether plastic-positive patients fared worse in one real cohort, the second whether particles damage cells/animals under controlled dosing. Treating one as confirming the other assumes the human association is causal and the mechanism operates at human exposure \u2014 neither established.", "simple": "The human heart study and the lab-animal studies measure different things: whether people with plastic in their plaque did worse, versus whether plastic damages cells and animals at set doses. Treating each as backing up the other assumes the human link is causal and the lab harm happens at real human amounts \u2014 neither of which is settled."}}]};

const STR_RANK = { strong: 0, moderate: 1, thin: 2 };
const DIR_LABEL = { SUPPORTS: "FOR", CHALLENGES: "AGAINST", COMPLICATES: "COMPLICATES" };
const DIR_COLOR = { SUPPORTS: "#5c7a64", CHALLENGES: "#a85d52", COMPLICATES: "#9a8a55" };
const TEASER_KINDS = new Set(["cross-dimension", "empirical-contradiction"]);

function buildIndex(d) {
  const nodeById = {}; d.nodes.forEach(n => (nodeById[n.id] = n));
  const findingById = {}; d.findings.forEach(f => (findingById[f.finding_id] = f));
  const findingsByNode = {};
  d.findings.forEach(f => { (findingsByNode[f.node_id] ||= []).push(f); });
  const subtree = {};
  const collect = (id) => {
    if (subtree[id]) return subtree[id];
    const set = new Set((findingsByNode[id] || []).map(f => f.finding_id));
    (nodeById[id].children || []).forEach(c => collect(c).forEach(x => set.add(x)));
    return (subtree[id] = set);
  };
  d.nodes.forEach(n => collect(n.id));
  const tnAdj = {};
  d.tensions.forEach(t => {
    (tnAdj[t.a] ||= []).push({ partner: t.b, kind: t.kind, note: t.note });
    (tnAdj[t.b] ||= []).push({ partner: t.a, kind: t.kind, note: t.note });
  });
  return { nodeById, findingById, findingsByNode, subtree, tnAdj };
}

function orderFindings(list) {
  const rank = f => (STR_RANK[f.source_strength] ?? 1);
  const tag = list.map((f, i) => ({ f, i }));
  const by = (a, b) => rank(a.f) - rank(b.f) || a.i - b.i;
  const S = tag.filter(x => x.f.direction === "SUPPORTS").sort(by);
  const C = tag.filter(x => x.f.direction === "CHALLENGES").sort(by);
  const X = tag.filter(x => x.f.direction === "COMPLICATES").sort(by);
  const inter = []; let i = 0;
  while (i < S.length || i < C.length) { if (i < S.length) inter.push(S[i]); if (i < C.length) inter.push(C[i]); i++; }
  return [...inter, ...X].map(x => x.f);
}

const pick = (x, reg) => (x && typeof x === "object" && !Array.isArray(x) && ("research" in x))
  ? (x[reg] ?? x.research) : x;

const crumb = (n, reg) => n.role === "topic" ? "Start"
  : pick(n.question, reg).replace(/\?+$/, "").replace(/^(How|Does|What|Are|Do)\s+/i, "").trim().slice(0, 24);

export default function App() {
  const idx = useMemo(() => buildIndex(DATA), []);
  const { nodeById, findingById, findingsByNode, subtree, tnAdj } = idx;

  const [current, setCurrent] = useState("n_root");
  const [reg, setReg] = useState("research");
  const P = x => pick(x, reg);
  const [path, setPath] = useState(["n_root"]);
  const [phase, setPhase] = useState("reading");
  const [step, setStep] = useState(0);
  const [seen, setSeen] = useState({});
  const [conf, setConf] = useState({});
  const [, setChoices] = useState({});
  const [visited, setVisited] = useState({ n_root: true });
  const [teasers, setTeasers] = useState(null);
  const [pendingChild, setPendingChild] = useState(null);
  const [slider, setSlider] = useState(50);

  const node = nodeById[current];
  const ordered = useMemo(() => orderFindings(findingsByNode[current] || []), [current]);

  useEffect(() => {
    if (phase === "reading" && ordered[step]) {
      const fid = ordered[step].finding_id;
      setSeen(s => (s[fid] ? s : { ...s, [fid]: true }));
    }
  }, [current, phase, step, ordered]);

  function enter(nodeId, newPath) {
    const n = nodeById[nodeId];
    setCurrent(nodeId); setPath(newPath); setStep(0); setTeasers(null); setPendingChild(null);
    setVisited(v => (v[nodeId] ? v : { ...v, [nodeId]: true }));
    if (n.scored) {
      const c = conf[nodeId] || {};
      if (c.posterior != null) setPhase("stop");
      else if (c.prior != null) setPhase("reading");
      else { setPhase("prior"); setSlider(50); }
    } else {
      const comps = (findingsByNode[nodeId] || []).filter(f => f.direction === "COMPLICATES");
      setPhase(comps.every(f => seen[f.finding_id]) ? "depend" : "reading");
    }
  }

  function next() {
    if (step < ordered.length - 1) { setStep(step + 1); return; }
    if (node.scored) { setPhase("posterior"); setSlider(Math.round(((conf[current]?.prior) ?? 0.5) * 100)); }
    else setPhase("depend");
  }

  function chooseChild(childId) {
    setChoices(c => ({ ...c, [current]: childId }));
    const sibs = (node.children || []).filter(c => c !== childId);
    const seenIds = Object.keys(seen);
    const ts = [];
    sibs.forEach(sib => {
      const sf = subtree[sib] || new Set();
      seenIds.forEach(sid => (tnAdj[sid] || []).forEach(adj => {
        if (sf.has(adj.partner) && TEASER_KINDS.has(adj.kind))
          ts.push({ sibling: sib, label: nodeById[sib].question, note: adj.note, seenId: sid });
      }));
    });
    const uniq = [...new Map(ts.map(t => [t.sibling + t.note, t])).values()];
    if (uniq.length) { setTeasers(uniq); setPendingChild(childId); setPhase("teaser"); }
    else enter(childId, [...path, childId]);
  }

  const firedFor = fid => (tnAdj[fid] || []).filter(a => seen[a.partner] && a.partner !== fid);

  const seenCount = Object.keys(seen).length;
  const viewKey = current + "|" + phase + "|" + step + "|" + reg;

  // ---------- styles ----------
  const C = { bg: "#FAFAF8", ink: "#1b1a17", mut: "#9a978f", faint: "#c9c6bd", rule: "#e8e6df" };
  const serif = "Georgia, 'Times New Roman', serif";
  const mono = "ui-monospace, 'SF Mono', Menlo, monospace";
  const wrap = { minHeight: "100vh", background: C.bg, color: C.ink, display: "flex", flexDirection: "column", alignItems: "center", padding: "28px 20px 56px", boxSizing: "border-box" };
  const col = { width: "100%", maxWidth: 560, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", flex: 1 };
  const label = { fontFamily: mono, fontSize: 11, letterSpacing: "0.16em", textTransform: "uppercase", color: C.mut };
  const claim = { fontFamily: serif, fontSize: 21, lineHeight: 1.5, margin: "18px 0 0", maxWidth: 520 };
  const small = { fontFamily: mono, fontSize: 11.5, color: C.mut, lineHeight: 1.6 };
  const btn = { fontFamily: mono, fontSize: 12, letterSpacing: "0.06em", padding: "11px 26px", borderRadius: 999, border: "1px solid " + C.ink, background: "transparent", color: C.ink, cursor: "pointer", marginTop: 30 };
  const linkBtn = { fontFamily: mono, fontSize: 11.5, color: C.mut, background: "none", border: "none", cursor: "pointer", letterSpacing: "0.04em" };

  function Slider(onCommit, priorMark) {
    return (
      <div style={{ width: "100%", maxWidth: 380, marginTop: 26 }}>
        <div style={{ fontFamily: serif, fontSize: 40, lineHeight: 1 }}>{slider}<span style={{ fontSize: 18, color: C.mut }}>%</span></div>
        {priorMark != null && <div style={{ ...small, marginTop: 4 }}>you arrived at {Math.round(priorMark * 100)}%</div>}
        <input type="range" min="0" max="100" value={slider} onChange={e => setSlider(+e.target.value)} className="bue-range" style={{ width: "100%", marginTop: 18 }} />
        <div style={{ display: "flex", justifyContent: "space-between", ...label, fontSize: 10 }}>
          <span>certainly false</span><span>certainly true</span>
        </div>
        <button className="bue-btn" style={btn} onClick={onCommit}>Continue</button>
      </div>
    );
  }

  function Finding(f) {
    const fired = firedFor(f.finding_id);
    return (
      <>
        <div style={{ ...label, color: DIR_COLOR[f.direction], display: "flex", gap: 8, justifyContent: "center", alignItems: "center" }}>
          <span style={{ width: 6, height: 6, borderRadius: 6, background: DIR_COLOR[f.direction], display: "inline-block" }} />
          {DIR_LABEL[f.direction]} · {f.evidence_type} · {f.source_strength}
        </div>
        <p style={claim}>{P(f.claim_paragraph)}</p>
        {P(f.effect_size) && P(f.effect_size) !== "qualitative" && <div style={{ ...small, marginTop: 12 }}>{P(f.effect_size)}</div>}
        <div style={{ ...small, fontStyle: "italic", marginTop: 12, maxWidth: 460 }}>{P(f.caveat)}</div>
        <div style={{ ...small, marginTop: 10, color: C.faint }}>{f.source_citation}</div>
        {fired.map((t, i) => (
          <div key={i} style={{ marginTop: 22, paddingTop: 16, borderTop: "1px solid " + C.rule, maxWidth: 460 }}>
            <div style={{ ...label, color: C.ink }}>tension · {t.kind}</div>
            <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
          </div>
        ))}
        <button className="bue-btn" style={btn} onClick={next}>{step < ordered.length - 1 ? "Next" : (node.scored ? "Rate again" : "So it depends →")}</button>
      </>
    );
  }

  function Heading() {
    if (node.role === "topic") return null;
    if (node.scored) return (
      <>
        <div style={{ ...small, marginBottom: 6 }}>{P(node.question)}</div>
        <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.claim_evaluated)}</div>
      </>
    );
    return <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.question)}</div>;
  }

  // ---------- body per phase ----------
  let body;
  if (phase === "reading") {
    body = <>
      {current === "n_root" && step === 0 && (
        <div style={{ marginBottom: 26 }}>
          <div style={{ fontFamily: serif, fontSize: 26, lineHeight: 1.35, maxWidth: 480 }}>A place to test a belief against the evidence.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, lineHeight: 1.7 }}>It won't hand you a verdict. It shows what the research says, where it's thin, and where it pulls in different directions — you do the believing.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, color: C.faint }}>Leaves out: housing, public-service load, gains to employers, origin-country effects, politics. Absence is scope, not proof of no effect.</div>
        </div>
      )}
      {current !== "n_root" && Heading()}
      <div style={{ height: 14 }} />
      {ordered[step] && Finding(ordered[step])}
    </>;
  } else if (phase === "depend") {
    const opts = node.children || [];
    const exploredN = opts.filter(cid => visited[cid]).length;
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 30 }}>It depends. On what?</div>
      <div style={{ ...small, marginTop: 6 }}>Pick the aspect that matters most to you — the choice itself is telling.</div>
      {exploredN > 0 && <div style={{ ...small, marginTop: 4, color: C.faint }}>You've explored {exploredN} of {opts.length}.</div>}
      <div style={{ marginTop: 22, width: "100%", maxWidth: 460 }}>
        {opts.map(cid => {
          const vis = !!visited[cid];
          const post = conf[cid] && conf[cid].posterior;
          const tag = vis ? (post != null ? "visited · you left it at " + Math.round(post * 100) + "%" : "visited") : null;
          return (
            <button key={cid} className={"bue-choice" + (vis ? " bue-visited" : "")} onClick={() => chooseChild(cid)}>
              <span>
                <span className="bue-qtext">{P(nodeById[cid].question)}</span>
                {nodeById[cid].evidence_quality === "thin" && <span style={{ ...label, display: "block", marginTop: 5, color: C.faint }}>empirically thin</span>}
                {tag && <span className="bue-visited-tag">{tag}</span>}
              </span>
              <span className="bue-arrow">{vis ? "↺" : "→"}</span>
            </button>
          );
        })}
      </div>
    </>;
  } else if (phase === "teaser") {
    body = <>
      <div style={{ ...label }}>before you narrow</div>
      <div style={{ fontFamily: serif, fontSize: 21, lineHeight: 1.5, marginTop: 16, maxWidth: 500 }}>
        What you've seen pulls against evidence you're about to leave behind.
      </div>
      {teasers.map((t, i) => (
        <div key={i} style={{ marginTop: 20, maxWidth: 460 }}>
          <div style={{ ...label, color: C.ink }}>under → {crumb(nodeById[t.sibling], reg)}</div>
          <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
        </div>
      ))}
      <div style={{ ...small, marginTop: 22 }}>You can come back to it later — nothing you've read is lost.</div>
      <button className="bue-btn" style={btn} onClick={() => enter(pendingChild, [...path, pendingChild])}>Continue →</button>
    </>;
  } else if (phase === "prior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>before the evidence</div>
      <div style={{ ...small, marginTop: 6 }}>How true does this feel right now?</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), prior: slider / 100 } })); setPhase("reading"); setStep(0); })}
    </>;
  } else if (phase === "posterior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>now, having read it</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), posterior: slider / 100 } })); setPhase("stop"); }, conf[current]?.prior)}
    </>;
  } else if (phase === "stop") {
    const c = conf[current] || {};
    const d = c.posterior != null && c.prior != null ? Math.round((c.posterior - c.prior) * 100) : null;
    const seenHere = (findingsByNode[current] || []).map(f => f.finding_id);
    const tens = [];
    seenHere.forEach(fid => firedFor(fid).forEach(t => tens.push(t)));
    const uniqT = [...new Map(tens.map(t => [P(t.note), t])).values()];
    const parentFork = [...path].reverse().find(id => !nodeById[id].scored);
    const depObj = node.depends_on;
    const isLeafStop = depObj && (depObj.research || "").startsWith("LEAF");
    body = <>
      {Heading()}
      <div style={{ marginTop: 26, paddingTop: 20, borderTop: "1px solid " + C.rule, maxWidth: 480 }}>
        <div style={{ ...label }}>where the research runs out</div>
        <div style={{ fontFamily: serif, fontSize: 16, lineHeight: 1.6, marginTop: 12, color: "#3a3a36" }}>
          {isLeafStop
            ? P(depObj).replace(/^LEAF:\s*/, "")
            : "This is the edge of what the evidence settles. What's left is a judgment about how much weight to give each piece — a values question, not an empirical one."}
        </div>
      </div>
      {d != null && (
        <div style={{ marginTop: 24 }}>
          <div style={{ ...label }}>your move</div>
          <div style={{ fontFamily: serif, fontSize: 22, marginTop: 8 }}>
            {Math.round(c.prior * 100)}% <span style={{ color: C.mut }}>→</span> {Math.round(c.posterior * 100)}%
          </div>
          <div style={{ ...small, marginTop: 4 }}>{d === 0 ? "held steady" : (d > 0 ? "+" : "") + d + " points"}</div>
        </div>
      )}
      {uniqT.length > 0 && (
        <div style={{ marginTop: 24, maxWidth: 460 }}>
          <div style={{ ...label }}>still unresolved</div>
          {uniqT.map((t, i) => <div key={i} style={{ fontFamily: serif, fontSize: 14.5, lineHeight: 1.5, marginTop: 10, color: "#555" }}>{P(t.note)}</div>)}
        </div>
      )}
      <div style={{ marginTop: 30, display: "flex", gap: 22 }}>
        {parentFork && parentFork !== current &&
          <button className="bue-link" onClick={() => { const i = path.indexOf(parentFork); enter(parentFork, path.slice(0, i + 1)); }}>← explore another branch</button>}
      </div>
    </>;
  }

  return (
    <div style={wrap}>
      <style>{`
        @keyframes bueEnter { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: none; } }
        .bue-fade { animation: bueEnter .44s cubic-bezier(.2,.7,.2,1) both; }
        @media (prefers-reduced-motion: reduce) { .bue-fade { animation: none; } }
        .bue-range { -webkit-appearance: none; appearance: none; height: 2px; background: ${C.faint}; outline: none; border-radius: 2px; }
        .bue-range::-webkit-slider-thumb { -webkit-appearance: none; width: 18px; height: 18px; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-range::-moz-range-thumb { width: 18px; height: 18px; border: none; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-crumb { text-decoration: underline; text-underline-offset: 2px; text-decoration-style: dotted; text-decoration-color: ${C.faint}; }
        .bue-crumb:hover { color: ${C.ink} !important; text-decoration-color: ${C.ink}; }
        .bue-crumb.bue-current { text-decoration: none; cursor: default; }
        .bue-btn { transition: background .15s, color .15s; }
        .bue-btn:hover { background: ${C.ink}; color: ${C.bg}; }
        .bue-link { color: ${C.ink}; background: none; border: none; padding: 0; cursor: pointer; font-family: ${mono}; font-size: 11.5px; letter-spacing: .04em; text-decoration: underline; text-underline-offset: 3px; }
        .bue-link:hover { opacity: .6; }
        .bue-choice { display: flex; align-items: center; justify-content: center; gap: 12px; width: 100%; box-sizing: border-box; text-align: center; background: #ffffff; border: 1px solid ${C.rule}; border-radius: 12px; padding: 16px 18px; margin-top: 10px; cursor: pointer; font-family: ${serif}; font-size: 17px; color: ${C.ink}; line-height: 1.4; transition: border-color .15s, background .15s, box-shadow .15s; }
        .bue-choice:hover { border-color: ${C.ink}; box-shadow: 0 1px 0 ${C.ink}; }
        .bue-choice .bue-arrow { color: ${C.mut}; font-family: ${mono}; font-size: 13px; }
        .bue-choice:hover .bue-arrow { color: ${C.ink}; }
        .bue-choice.bue-visited { background: #f2f3f6; border-color: #dcdde6; }
        .bue-choice.bue-visited .bue-qtext { color: ${C.mut}; }
        .bue-choice.bue-visited:hover { border-color: #6a6f86; box-shadow: 0 1px 0 #6a6f86; }
        .bue-visited-tag { display: block; margin-top: 6px; font-family: ${mono}; font-size: 10px; letter-spacing: .12em; text-transform: uppercase; color: #6a6f86; }
        .bue-seg { display: inline-flex; border: 1px solid ${C.rule}; border-radius: 999px; overflow: hidden; }
        .bue-seg button { font-family: ${mono}; font-size: 10.5px; letter-spacing: .08em; text-transform: uppercase; padding: 5px 13px; background: none; border: none; cursor: pointer; color: ${C.mut}; transition: background .15s, color .15s; }
        .bue-seg button:hover { color: ${C.ink}; }
        .bue-seg button.bue-on { background: ${C.ink}; color: ${C.bg}; }
      `}</style>

      {/* language toggle */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <span style={{ ...label, fontSize: 10, color: C.faint }}>language</span>
        <div className="bue-seg">
          {[["research", "Research"], ["simple", "Plain"]].map(([k, lab]) => (
            <button key={k} className={reg === k ? "bue-on" : ""} onClick={() => setReg(k)}>{lab}</button>
          ))}
        </div>
      </div>

      {/* breadcrumb */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", flexWrap: "wrap", gap: 6, marginBottom: 30 }}>
        {path.map((id, i) => (
          <span key={id} style={{ ...label, fontSize: 10.5 }}>
            {i > 0 && <span style={{ color: C.faint, margin: "0 6px" }}>{"›"}</span>}
            <button className={"bue-crumb" + (i === path.length - 1 ? " bue-current" : "")}
              onClick={() => { if (i !== path.length - 1) enter(id, path.slice(0, i + 1)); }}
              style={{ background: "none", border: "none", padding: 0, cursor: "pointer", color: i === path.length - 1 ? C.ink : C.mut, ...label, fontSize: 10.5 }}>
              {crumb(nodeById[id], reg)}
            </button>
          </span>
        ))}
      </div>

      <div style={col}>
        <div key={viewKey} className="bue-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
          {body}
        </div>
      </div>

      <div style={{ ...label, fontSize: 10, color: C.faint, marginTop: 40 }}>{seenCount} of {DATA.findings.length} findings seen</div>
    </div>
  );
}
